def _encode_advertising_data(*adv_fields):
    """Encode advertising data payload."""
    payload = bytearray()
    for ad_type, value in adv_fields:
        if isinstance(value, str):
            value = value.encode('utf-8')
        payload += struct.pack("BB", len(value) + 1, ad_type) + value
    return bytes(payload)


class BLEDeviceServer:
    """BLE GATT Server for IoT device control."""

    def __init__(self, device_name="ESP32-IoT-Device"):
        self._device_name = device_name
        self._ble = bluetooth.BLE()
        self._ble.active(True)
        self._ble.irq(self._irq_handler)

        self._connections = set()
        self._sensor_manager = SensorManager()

        # Notification tracking
        self._notify_enabled = False
        self._notify_interval_ms = 5000
        self._last_notify_time = 0

        # Register GATT services
        self._register_services()

        # Start advertising
        self._advertise()

        print("BLE Device Server '{}' started".format(self._device_name))
        print("Waiting for connections...")

    def _register_services(self):
        """Register all GATT services and characteristics."""

        # Device Control Service
        _device_control_service = (
            _DEVICE_CONTROL_SERVICE_UUID,
            (
                # Sensor Data - readable + notify
                (_SENSOR_DATA_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                # Control Command - writable + readable (for response)
                (_CONTROL_CMD_CHAR_UUID, _FLAG_WRITE | _FLAG_WRITE_NO_RESPONSE | _FLAG_READ),
                # Device Status - readable + notify
                (_DEVICE_STATUS_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                # Configuration - readable + writable
                (_CONFIG_CHAR_UUID, _FLAG_READ | _FLAG_WRITE),
            ),
        )

        # Device Information Service (standard)
        _device_info_service = (
            _DEVICE_INFO_SERVICE_UUID,
            (
                (_MANUFACTURER_NAME_CHAR_UUID, _FLAG_READ),
                (_MODEL_NUMBER_CHAR_UUID, _FLAG_READ),
                (_FIRMWARE_REV_CHAR_UUID, _FLAG_READ),
            ),
        )

        # Battery Service (standard)
        _battery_service = (
            _BATTERY_SERVICE_UUID,
            (
                (_BATTERY_LEVEL_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
            ),
        )

        # Register all services at once
        (
            (
                self._sensor_data_handle,
                self._control_cmd_handle,
                self._device_status_handle,
                self._config_handle,
            ),
            (
                self._manufacturer_handle,
                self._model_handle,
                self._firmware_handle,
            ),
            (
                self._battery_handle,
            ),
        ) = self._ble.gatts_register_services([
            _device_control_service,
            _device_info_service,
            _battery_service,
        ])

        # Set initial values for Device Info characteristics
        self._ble.gatts_write(self._manufacturer_handle, b"ESP32 IoT Corp")
        self._ble.gatts_write(self._model_handle, b"ESP32-CTRL-V1")
        self._ble.gatts_write(self._firmware_handle, b"1.0.0")

        # Set initial sensor and status data
        self._update_sensor_data()
        self._update_device_status()
        self._update_battery_level()

        # Set larger buffer for characteristics that receive/send JSON
        self._ble.gatts_set_buffer(self._sensor_data_handle, 512)
        self._ble.gatts_set_buffer(self._control_cmd_handle, 512)
        self._ble.gatts_set_buffer(self._device_status_handle, 512)
        self._ble.gatts_set_buffer(self._config_handle, 512)

        print("GATT services registered successfully")

    def _irq_handler(self, event, data):
        """Handle BLE IRQ events."""

        if event == _IRQ_CENTRAL_CONNECT:
            conn_handle, addr_type, addr = data
            addr_str = ":".join("{:02x}".format(b) for b in addr)
            print("Connected: handle={}, addr={}".format(conn_handle, addr_str))
            self._connections.add(conn_handle)
            self._notify_enabled = True
            # Update data on new connection
            self._update_sensor_data()
            self._update_device_status()
            # Continue advertising for multiple connections
            self._advertise()

        elif event == _IRQ_CENTRAL_DISCONNECT:
            conn_handle, addr_type, addr = data
            addr_str = ":".join("{:02x}".format(b) for b in addr)
            print("Disconnected: handle={}, addr={}".format(conn_handle, addr_str))
            self._connections.discard(conn_handle)
            if not self._connections:
                self._notify_enabled = False
            # Restart advertising
            self._advertise()

        elif event == _IRQ_GATTS_WRITE:
            conn_handle, attr_handle = data
            value = self._ble.gatts_read(attr_handle)

            if attr_handle == self._control_cmd_handle:
                print("Control command received: {}".format(value))
                self._handle_control_command(conn_handle, value)

            elif attr_handle == self._config_handle:
                print("Config update received: {}".format(value))
                self._handle_config_update(conn_handle, value)

        elif event == _IRQ_GATTS_READ_REQUEST:
            conn_handle, attr_handle = data
            # Update data before read
            if attr_handle == self._sensor_data_handle:
                self._update_sensor_data()
            elif attr_handle == self._device_status_handle:
                self._update_device_status()
            elif attr_handle == self._battery_handle:
                self._update_battery_level()

    def _handle_control_command(self, conn_handle, value):
        """Process incoming control command and send response."""
        try:
            cmd_str = value.decode('utf-8')
            response = self._sensor_manager.execute_command(cmd_str)
            # Write response back to the command characteristic
            self._ble.gatts_write(self._control_cmd_handle, response.encode('utf-8'))
            # Update status after command execution
            self._update_device_status()
            self._notify_status(conn_handle)
        except Exception as e:
            print("Command handling error:", e)
            error_resp = json.dumps({"status": "error", "message": str(e)})
            self._ble.gatts_write(self._control_cmd_handle, error_resp.encode('utf-8'))

    def _handle_config_update(self, conn_handle, value):
        """Process incoming configuration update."""
        try:
            config_str = value.decode('utf-8')
            response = self._sensor_manager.apply_config(config_str)
            # Write response back
            self._ble.gatts_write(self._config_handle, response.encode('utf-8'))
        except Exception as e:
            print("Config handling error:", e)
            error_resp = json.dumps({"status": "error", "message": str(e)})
            self._ble.gatts_write(self._config_handle, error_resp.encode('utf-8'))

    def _update_sensor_data(self):
        """Update sensor data characteristic."""
        data = self._sensor_manager.get_sensor_data()
        self._ble.gatts_write(self._sensor_data_handle, data.encode('utf-8'))

    def _update_device_status(self):
        """Update device status characteristic."""
        status = self._sensor_manager.get_device_status()
        self._ble.gatts_write(self._device_status_handle, status.encode('utf-8'))

    def _update_battery_level(self):
        """Update battery level characteristic."""
        level = self._sensor_manager.read_battery_level()
        self._ble.gatts_write(self._battery_handle, struct.pack("B", level))

    def _notify_sensor_data(self):
        """Send sensor data notification to all connected clients."""
        if not self._connections:
            return
        self._update_sensor_data()
        data = self._ble.gatts_read(self._sensor_data_handle)
        for conn_handle in self._connections:
            try:
                self._ble.gatts_notify(conn_handle, self._sensor_data_handle, data)
            except Exception as e:
                print("Notify error (sensor) conn {}:".format(conn_handle), e)

    def _notify_status(self, conn_handle=None):
        """Send status notification."""
        self._update_device_status()
        data = self._ble.gatts_read(self._device_status_handle)
        targets = [conn_handle] if conn_handle else self._connections
        for ch in targets:
            try:
                self._ble.gatts_notify(ch, self._device_status_handle, data)
            except Exception as e:
                print("Notify error (status) conn {}:".format(ch), e)

    def _notify_battery(self):
        """Send battery level notification."""
        if not self._connections:
            return
        self._update_battery_level()
        data = self._ble.gatts_read(self._battery_handle)
        for conn_handle in self._connections:
            try:
                self._ble.gatts_notify(conn_handle, self._battery_handle, data)
            except Exception as e:
                print("Notify error (battery) conn {}:".format(conn_handle), e)

    def _advertise(self):
        """Start BLE advertising."""
        # Build advertising payload
        adv_data = _encode_advertising_data(
            (_ADV_TYPE_FLAGS, struct.pack("B", 0x06)),  # General discoverable + BR/EDR not supported
            (_ADV_TYPE_NAME, self._device_name),
            (_ADV_TYPE_APPEARANCE, struct.pack("<H", 0x0540)),  # Generic Sensor appearance
        )

        # Scan response with service UUIDs
        scan_resp = _encode_advertising_data(
            (_ADV_TYPE_UUID128_COMPLETE, bytes(_DEVICE_CONTROL_SERVICE_UUID)),
        )

        self._ble.gap_advertise(
            100_000,  # Advertising interval in microseconds (100ms)
            adv_data=adv_data,
            resp_data=scan_resp,
            connectable=True,
        )
        print("Advertising started")

    def process(self):
        """Main processing loop - call periodically to handle notifications."""
        current_time = time.ticks_ms()

        if self._notify_enabled and self._connections:
            if time.ticks_diff(current_time, self._last_notify_time) >= self._notify_interval_ms:
                self._last_notify_time = current_time
                self._notify_sensor_data()
                self._notify_battery()

    def get_connection_count(self):
        """Return number of active connections."""
        return len(self._connections)

    def is_connected(self):
        """Check if any client is connected."""
        return len(self._connections) > 0

    def set_notify_interval(self, interval_ms):
        """Set the notification interval in milliseconds."""
        self._notify_interval_ms = max(1000, interval_ms)
        print("Notify interval set to {}ms".format(self._notify_interval_ms))

    def stop(self):
        """Stop the BLE server."""
        self._ble.gap_advertise(None)
        self._ble.active(False)
        print("BLE server stopped")


