    # Status LED blink to show we're running
    status_led = None
    try:
        status_led = machine.Pin(2, machine.Pin.OUT)
    except Exception:
        pass

    blink_counter = 0
    status_print_counter = 0

    try:
        while True:
            # Process BLE notifications
            server.process()

            # Blink status LED based on connection state
            blink_counter += 1
            if status_led:
                if server.is_connected():
                    # Solid on when connected
                    if not server._sensor_manager._device_on:
                        status_led.value(1)
                else:
                    # Slow blink when advertising
                    if blink_counter % 20 == 0:
                        status_led.value(not status_led.value())

            # Periodic status print
            status_print_counter += 1
            if status_print_counter >= 600:  # Every ~60 seconds
                status_print_counter = 0
                conn_count = server.get_connection_count()
                temp = server._sensor_manager.read_temperature()
                print("[Status] Connections: {}, Temp: {}°C".format(conn_count, temp))

            time.sleep_ms(100)

    except KeyboardInterrupt:
        print("\nShutting down BLE server...")
        server.stop()
        if status_led:
            status_led.value(0)
        print("Goodbye!")


